import React from "react";
import { useParams } from "react-router-dom";
import { useNavigate } from "react-router-dom";
import { APIs } from "../../Services/apis";
import { POST } from "../../Services/httpClient";
import LikeIcon from "../../assets/svg/thumb_up_black_24dp.svg";
import UnlikeIcon from "../../assets/svg/BlackUnlike.svg";
import RedUnlike from "../../assets/svg/thumb_down_black_24dp.svg";
import BLike from "../../assets/svg/LikeGrey.svg";

const user = localStorage.getItem("user");
const GUEST_USER_ID = localStorage.getItem("GUEST_USER_ID");
const numberOfPollLiked = localStorage.getItem("numberOfPollLiked");

const PersonPollMob = (props) => {
  const { val, onVote } = { ...props };
  const { slug } = useParams();
  let navigate = useNavigate();
  const likePoll = async (liked_poll, is_like) => {
    if (parseInt(numberOfPollLiked, 10) > 11) {
      navigate("/login");
    } else {
      let param;
      if (user) {
        param = {
          is_like: is_like,
          liked_poll: liked_poll,
          userid: JSON.parse(user)._id,
        };
      } else {
        param = {
          is_like: is_like,
          liked_poll: liked_poll,
          guest_user_id: GUEST_USER_ID,
        };
      }
      try {
        var res = await POST(APIs.LIKEUPDATE, param);
        if (res.status === 200) {
          onVote();
          if (!user) {
            const value = parseInt(numberOfPollLiked, 10);
            localStorage.setItem("numberOfPollLiked", value + 1);
          }
        } else {
          console.log(res.msg);
        }
      } catch (error) {
        console.log(error);
      }
    }
  };

  const handleSharing = (question, url) => {
    // console.log(url);
    if (navigator.share) {
      try {
        navigator
          .share({
            title: "The Poll App",
            text: question,
            url: url,
          })
          .then(() => console.log("Success"));
      } catch (error) {
        console.log(`Oops! I couldn't share to the world because: ${error}`);
      }
    } else {
      // fallback code
      console.log(
        "Web share is currently not supported on this browser. Please provide a callback"
      );
    }
  };

  return (
    <>
        <div className="personPollCard slide">
          <div className="row">
            <div className="col">
              <img src={val.answers[0].image} alt="og_imsge" className="personImg" />
              <div className="bottomLeft">
                <p className="percent">{val.likes_per === "" ? 0 : val.likes_per}%</p>
              </div>
            </div>
            <div className="col">
              <div className="topRight">{val.tags[0].tag_name}</div>
              <div className="pollCarouselContent">
                <div className="flex">
                  <h4 className="personName">{val.question}</h4>
                </div>
                <div className="flex likeUnlike">
                  <div
                    className="flex"
                    onClick={() => (val.isLiked ? null : likePoll(val._id, true))}
                    style={{ cursor: "pointer" }}
                  >
                    <img src={val.isLiked ? LikeIcon : BLike} alt="Like" width={50} height={50} />
                  </div>
                  <div
                    className="flex"
                    onClick={() => (val.isDisliked ? null : likePoll(val._id, false))}
                    style={{ cursor: "pointer" }}
                  >
                    <img
                      src={val.isDisliked ? RedUnlike : UnlikeIcon}
                      alt="Unlike"
                      width={50}
                      height={50}
                    />
                  </div>
                </div>
                <div className="flex">
                  <span className="percent">{val.likes_count}</span>
                  <h6 className="ttlVote">Total Votes</h6>
                </div>
                <div className="flex">
                  <button
                    className="shareBtn"
                    onClick={() => handleSharing(val.question, val.slug)}
                  >
                    Share
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
     
    </>
  );
};

export default PersonPollMob;
