import React, { useState, useEffect } from "react";
import BarWave from "react-cssfx-loading/lib/BarWave";
import Slider from "react-slick";
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";

import CardContainer from "../../components/CardContainer";
import Tab from "../../components/Tab";
import Header from "../../components/Header";
import { APIs } from "../../Services/apis";
import { POST } from "../../Services/httpClient";
import SinglePollContainer from "../../components/SinglePollContainer";
import PersonPollCarousel from "../../components/PersonPollMob";

const settings = {
  centerMode: false,
  centerPadding: "10px",
  slidesToShow: 3,
  speed: 500,
  slidesToScroll: 1,
  arrows: true,
  dots: false,
  infinite: false,
  autoplay: false,
  // speed: 10000,
  // autoplaySpeed: 10000,
  // cssEase: "linear",
  // pauseOnHover: true,
  responsive: [
    {
      breakpoint: 1050,
      settings: {
        arrows: false,
        slidesToShow: 2,
      },
    },
    {
      breakpoint: 770,
      settings: {
        arrows: false,
        slidesToShow: 2,
      },
    },
    {
      breakpoint: 480,
      centerMode: true,
      settings: {
        arrows: false,
        slidesToShow: 1,
      },
    },
  ],
};

const centerSetting = {
  className: "center",
  centerMode: true,
  slidesToShow: 1,
  focusOnSelect: true,
  dots: false,
  infinite: true,
  centerPadding: "40%",
  autoplay: true,
  responsive: [
    {
      breakpoint: 768,
      settings: {
        arrows: false,
        centerMode: true,
        centerPadding: "40px",
        slidesToShow: 1,
      },
    },
    {
      breakpoint: 480,
      settings: {
        arrows: false,
        centerMode: true,
        centerPadding: "20px",
        slidesToShow: 1,
      },
    },
  ],
};

const Home = () => {
  const [loading, setLoading] = useState(false);
  const [showSection, setShowSection] = useState(true);
  const [data, setData] = useState([]);
  const [GuestUserId, setGuestUserId] = useState([]);

  useEffect(() => {
    const GUEST_USER_ID = localStorage.getItem("GUEST_USER_ID");
    if (!GUEST_USER_ID) {
      const GUEST_USER_ID =
        Math.random()
          .toString(36)
          .substring(2, 17) +
        Math.random()
          .toString(36)
          .substring(2, 15);

      localStorage.setItem("GUEST_USER_ID", GUEST_USER_ID);
      setGuestUserId(GUEST_USER_ID);
    }
    fetchdata();
  }, []);

  const fetchdata = async () => {
    const GUEST_USER_ID = await localStorage.getItem("GUEST_USER_ID");

    var res = await POST(APIs.POLLLIST, {
      status: 3,
      guest_user_id: GUEST_USER_ID,
    });
    if (res.status === 200) {
      if (res.data) setData(res.data);
    }
    setLoading(true);
  };

  console.log(data.data.question_type, "Data from TestHome");

  return (
    <>
      <Header heading={"HOME"} />
      {loading ? (
        <>
          <div className="container desk-slider">
            <Slider {...settings}>
              {data.map((val, index) => {
                return (
                  <SinglePollContainer
                    onVote={fetchdata}
                    val={val}
                    key={index}
                  />
                );
              })}
            </Slider>
          </div>

          <div className="container slider center mob-slider">
            <Slider {...centerSetting}>
              {data.map((val, index) => {
                return (
                  <PersonPollCarousel
                    onVote={fetchdata}
                    val={val}
                    key={index}
                  />
                );
              })}
            </Slider>
          </div>

          {/* <SinglePollContainer onVote={fetchdata} data={data} /> */}
          {/* <PersonPollCarousel /> */}
          {/* <div className="hrLine" /> */}
          <Tab />
          {data.map((val, index) => {
            return <CardContainer onVote={fetchdata} val={val} key={index} />;
          })}
        </>
      ) : (
        <div className="loadingDiv">
          <BarWave color="#4BD97E" width="100px" height="100px" />
        </div>
      )}
    </>
  );
};

export default Home;
